```java
public static long solve(long[] nums, long k) {
    long total = 0;
    long mod = 0;
    long minSum = Long.MAX_VALUE;

    for (long num : nums) {
        total += num;
        mod = (mod + num) % k;

        if (mod == 0) {
            minSum = Math.min(minSum, total);
        } else {
            minSum = Math.min(minSum, total - mod);
        }
    }

    return minSum;
}
