public static long solve(long[] nums, long k) {
    long total = 0;
    for (long num : nums) {
        total += num;
    }

    long[] prefixMod = new long[nums.length];
    prefixMod[0] = (nums[0] % k + k) % k;
    for (int i = 1; i < nums.length; i++) {
        prefixMod[i] = (prefixMod[i - 1] + (nums[i] % k)) % k;
    }

    long[] count = new long[k];
    for (long mod : prefixMod) {
        count[(int) mod]++;
    }

    long minSum = total;
    for (int i = 0; i < k; i++) {
        if (count[i] > 0) {
            minSum = Math.min(minSum, total - (count[i] * i));
        }
    }

    return minSum;
}
