public static long solve(long[] nums, long k) {
    long[] prefixSum = new long[nums.length + 1];
    for (int i = 0; i < nums.length; i++) {
        prefixSum[i + 1] = prefixSum[i] + nums[i];
    }

    long[] mod = new long[nums.length + 1];
    for (int i = 0; i < nums.length; i++) {
        mod[i + 1] = (prefixSum[i + 1] % k + k) % k; // Ensure non-negative mod
    }

    long[] count = new long[k];
    for (int i = 0; i <= nums.length; i++) {
        count[(int) mod[i]]++;
    }

    long result = 0;
    for (int i = 0; i < nums.length; i++) {
        result += nums[i];
    }

    for (int i = 1; i < k; i++) {
        if (count[i] > 0) {
            result -= (count[i] * i) % k;
        }
    }

    return result;
}
