public static long solve(long[] nums, long k) {
    long[] prefixMod = new long[nums.length];
    prefixMod[0] = nums[0] % k;
    for (int i = 1; i < nums.length; i++) {
        prefixMod[i] = (prefixMod[i - 1] + nums[i]) % k;
    }

    long minSum = Long.MAX_VALUE;
    long[] modCount = new long[k];
    modCount[0] = 1;

    for (int i = 0; i < nums.length; i++) {
        long mod = prefixMod[i];
        if (mod == 0) {
            minSum = Math.min(minSum, 0);
        } else {
            modCount[(int) mod]++;
        }
    }

    for (int i = 0; i < k; i++) {
        if (modCount[i] > 0) {
            minSum = Math.min(minSum, (long) modCount[i] * i);
        }
    }

    return minSum;
}
